"use strict";(self.webpackChunkmagento2_hyva_jewellery_theme_docs=self.webpackChunkmagento2_hyva_jewellery_theme_docs||[]).push([[6932],{5190(e,t,o){o.r(t),o.d(t,{comp:()=>a,data:()=>n});var r=o(641);const s={},a=(0,o(6262).A)(s,[["render",function(e,t){return(0,r.uX)(),(0,r.CE)("div",null,[...t[0]||(t[0]=[(0,r.Fv)('<h1 id="faq" tabindex="-1"><a class="header-anchor" href="#faq"><span>FAQ</span></a></h1><p><strong>Is Adornment a standalone theme or a child theme?</strong> It works with Hyva. Hyva must be installed first.</p><p><strong>Do I need coding skills to build the homepage?</strong> No. The <strong>Homepage Configurator</strong> and <strong>Header &amp; Footer Builder</strong> are visual admin tools.</p><p><strong>How many homepage sections can I add?</strong> As many as you like. They show from top to bottom based on <strong>Sort Order</strong>. There are 10 section types to mix and match.</p><p><strong>Can I show different homepages per store view?</strong> Yes. Use <strong>Store ID</strong> to control where a section appears. Use <code>0</code> for all stores.</p><p><strong>Where are mega menu settings saved?</strong> They are saved from <strong>Content -&gt; Homepage Configurator -&gt; Header &amp; Footer Builder</strong>.</p><p><strong>Can I use my own logo and colors?</strong> Yes. Set your logo in <strong>Header settings</strong>. Theme colors can be adjusted during setup or customization.</p><p><strong>Does it support swatches and configurable products?</strong> Yes — configurable products and swatches use the standard Magento + Hyva rendering, styled by the theme.</p><p><strong>Is the checkout included?</strong> The theme is designed to work with Hyva Checkout when Hyva Checkout is available on your store.</p><p><strong>How do I export a documentation page?</strong> Use the page-tools drawer (bottom-right) to export to <strong>PDF, Word, Markdown, HTML, RTF, or plain text</strong>, or press <kbd>P</kbd> for the PDF dialog. Search with <kbd>⌘</kbd>/<kbd>Ctrl</kbd>+<kbd>K</kbd>.</p><p><strong>What are the performance characteristics?</strong> The storefront is lightweight and designed for strong PageSpeed results.</p><p><strong>Where do I get support?</strong><a href="https://webkul.uvdesk.com/" target="_blank" rel="noopener noreferrer">Webkul support</a>.</p>',12)])])}]]),n=JSON.parse('{"path":"/help/faq.html","title":"FAQ","lang":"en-US","frontmatter":{},"headers":[],"git":{"contributors":[{"name":"anikesh kumar","username":"","email":"anikesh.kumar204@webkul.in","commits":1}],"changelog":[{"hash":"65ee1538c72e98b02c838952f96993746b91fe68","time":1783608557000,"email":"anikesh.kumar204@webkul.in","author":"anikesh kumar","message":"init"}]},"filePathRelative":"help/faq.md"}')}}]);